import React, { useEffect, useState } from 'react';
import { useHistory, useParams } from 'react-router-dom';
import { Nav, InputGroup, FormControl, Button } from 'react-bootstrap';
import styled from 'styled-components';
import './Detail.scss';
import { CSSTransition } from 'react-transition-group';
import { connect } from 'react-redux';

let 박스 = styled.div`
  padding: 20px;
`;

let 제목 = styled.h4`
  font-size: 25px;
  color: ${(props) => props.색상};
`;

function Detail(props) {
  useEffect(() => {
    let 타이머 = setTimeout(() => {
      alert변경(false);
    }, 2000);
  }, []);

  let [alert, alert변경] = useState(true);
  let [inputData, inputData변경] = useState('');
  let [누른탭, 누른탭변경] = useState(0);
  let [스위치, 스위치변경] = useState(false);
  let [구매수량, 수량변경] = useState(0);
  let 수량;

  let { id } = useParams();
  let history = useHistory();
  let 찾은상품 = props.shoes.find((x) => x.id == id);

  return (
    <div className='container'>
      <박스>
        <제목>Detail</제목>
      </박스>
      {alert === true ? (
        <div className='my-alert-yellow'>
          <p>재고가 얼마 남지 않았습니다</p>
        </div>
      ) : null}
      <div className='row'>
        <div className='col-md-6'>
          <img
            src={
              'https://codingapple1.github.io/shop/shoes' +
              (Number(id) + 1) +
              '.jpg'
            }
            width='100%'
            alt='shoes'
          />
        </div>
        <div className='col-md-6 mt-4'>
          <h4 className='pt-5'>{찾은상품.title}</h4>
          <p>{찾은상품.content}</p>
          <p>{찾은상품.price}원</p>
          <div>
            {props.재고[id] > 0 ? (
              <p>재고: {props.재고[id]}</p>
            ) : (
              <p>Sold Out</p>
            )}
          </div>
          <div>
            {' '}
            <InputGroup className='mb-3'>
              <FormControl
                placeholder='수량을 입력하세요'
                onChange={(e) => {
                  수량 = e.target.value;
                }}
              />
              <InputGroup.Append>
                <Button
                  variant='outline-secondary'
                  onClick={() => {
                    수량변경(수량);
                  }}
                >
                  확인
                </Button>
              </InputGroup.Append>
            </InputGroup>
          </div>
          <p>구매수량: {구매수량}개</p>
          <button
            className='btn btn-primary'
            onClick={() => {
              let new재고 = [...props.재고];
              if (구매수량 === 0) {
                console.log('원하는 구매 수량을 확인하세요');
              } else if (new재고[id] - 구매수량 < 0) {
                console.log('재고부족');
              } else {
                new재고[id] = new재고[id] - 구매수량;
                props.재고변경(new재고);
                props.dispatch({
                  type: '항목추가',
                  payload: {
                    id: 찾은상품.id,
                    name: 찾은상품.title,
                    quan: 구매수량,
                  },
                });
                수량변경(0);
                history.push('/cart');
              }
            }}
          >
            주문하기
          </button>
          <button
            className='btn btn-danger'
            onClick={() => {
              history.goBack();
            }}
          >
            뒤로가기
          </button>
        </div>
      </div>
      <Nav className='mt-5' variant='tabs' defaultActiveKey='link-0'>
        <Nav.Item>
          <Nav.Link
            eventKey='link-0'
            onClick={() => {
              스위치변경(false);
              누른탭변경(0);
            }}
          >
            Active
          </Nav.Link>
        </Nav.Item>
        <Nav.Item>
          <Nav.Link
            eventKey='link-1'
            onClick={() => {
              스위치변경(false);
              누른탭변경(1);
            }}
          >
            Active
          </Nav.Link>
        </Nav.Item>
      </Nav>

      <CSSTransition in={스위치} classNames='wow' timeout={1000}>
        <TabContent 누른탭={누른탭} 스위치변경={스위치변경} />
      </CSSTransition>
    </div>
  );
}

function TabContent(props) {
  useEffect(() => {
    props.스위치변경(true);
  });

  if (props.누른탭 === 0) {
    return <div>0번째 내용입니다</div>;
  } else if (props.누른탭 === 1) {
    return <div>1번째 내용입니다</div>;
  } else if (props.누른탭 === 2) {
    return <div>2번째 내용입니다</div>;
  }
}
function state를props화(state) {
  return {
    state: state,
  };
}

export default connect(state를props화)(Detail);
