import React, { useEffect, useState, memo } from 'react';
import { Table } from 'react-bootstrap';
import { connect } from 'react-redux';

function Cart(props) {
  let [pop, closePop] = useState(true);

  return (
    <div>
      <Table responsive>
        <thead>
          <tr>
            <th>#</th>
            <th>상품명</th>
            <th>수량</th>
            <th>변경</th>
          </tr>
        </thead>
        <tbody>
          {props.state.map((a, i) => {
            return (
              <tr key={i}>
                <td>{a.id}</td>
                <td>{a.name}</td>
                <td>{a.quan}</td>
                <td>
                  <button
                    onClick={() => {
                      props.dispatch({
                        type: '수량증가',
                        seletedItemID: a.id,
                      });
                    }}
                  >
                    +
                  </button>{' '}
                  <button
                    onClick={() => {
                      props.dispatch({ type: '수량감소', seletedItemID: a.id });
                    }}
                  >
                    -
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </Table>

      {pop === true ? (
        <div className='my-alert-yellow'>
          <p>지금 구매하시면 신규할인 20%</p>
          <button
            onClick={() => {
              closePop(false);
            }}
          >
            닫기
          </button>
        </div>
      ) : null}
      <Parent 이름='존박' 나이='20'></Parent>
    </div>
  );
}

function Parent(props) {
  return (
    <div>
      <Child1 이름={props.이름}></Child1>
      <Child2 나이={props.나이}></Child2>
    </div>
  );
}

function Child1(props) {
  useEffect(() => {
    console.log('렌더링됨1');
  });
  return <div>{props.이름}</div>;
}

let Child2 = memo(function (props) {
  useEffect(() => {
    console.log('렌더링됨2');
  });
  return <div>{props.나이}</div>;
});

function state를props화(state) {
  return {
    state: state,
  };
}

export default connect(state를props화)(Cart);

